import { useParams, useNavigate } from "react-router-dom";
import { useEffect, useState } from "react";
import "./ViewEmployee.css";

function ViewEmployee() {
  const { id } = useParams();
  const navigate = useNavigate();
  const [employee, setEmployee] = useState(null);

  useEffect(() => {
    const employees = JSON.parse(localStorage.getItem("employees")) || [];

    const foundEmployee = employees.find(
      (emp) => String(emp.id) === String(id)
    );

    setEmployee(foundEmployee);
  }, [id]);

  if (!employee) {
    return <p style={{ padding: "20px" }}>Employee not found</p>;
  }

  return (
    <div className="view-employee-page">
      <h2>Employee Details</h2>

      <div className="employee-card">

        {/* BASIC DETAILS */}
        <div className="employee-info">
          <p><strong>Name:</strong> {employee.firstName} {employee.lastName}</p>
          <p><strong>Email:</strong> {employee.email}</p>
          <p><strong>Employee ID:</strong> {employee.empId}</p>
          <p><strong>Date of Birth:</strong> {employee.dob}</p>
          <p><strong>Gender:</strong> {employee.gender}</p>
          <p><strong>Department:</strong> {employee.department}</p>
          <p><strong>Marital Status:</strong> {employee.maritalStatus}</p>
          <p><strong>Designation:</strong> {employee.designation}</p>
          <p><strong>Salary:</strong> {employee.salary}</p>
          <p><strong>Role:</strong> {employee.role}</p>
        </div>

        {/* BANK DETAILS */}
        <h3>Bank Details</h3>
        <p><b>Bank Name:</b> {employee.bankName || "Not Provided"}</p>
        <p><b>Account Number:</b> {employee.accountNumber || "Not Provided"}</p>
        <p><b>IFSC:</b> {employee.ifsc || "Not Provided"}</p>

        {/* EDUCATION */}
        <h3>Educational Details</h3>
        <p><b>Qualification:</b> {employee.qualification || "Not Provided"}</p>
        <p><b>University:</b> {employee.university || "Not Provided"}</p>
        <p><b>Passing Year:</b> {employee.passingYear || "Not Provided"}</p>

      </div>

      <button className="back-btn" onClick={() => navigate(-1)}>
        Back
      </button>
    </div>
  );
}

export default ViewEmployee;
